const steps = $input.all().map(i => i.json).sort((a, b) => parseInt(a.step_order) - parseInt(b.step_order));
const results = steps.map((step, i) => {
  const entered = parseInt(step.users_entered || 0);
  const prevEntered = i > 0 ? parseInt(steps[i-1].users_entered || 1) : entered;
  const topOfFunnel = parseInt(steps[0].users_entered || 1);
  const step_cr = i > 0 ? ((entered / prevEntered) * 100).toFixed(1) : 100;
  const overall_cr = ((entered / topOfFunnel) * 100).toFixed(1);
  const drop_off = i > 0 ? prevEntered - entered : 0;
  return { ...step, step_conversion_rate: parseFloat(step_cr), overall_conversion_rate: parseFloat(overall_cr), drop_off_users: drop_off };
});
const worstStep = results.slice(1).reduce((a, b) => a.step_conversion_rate < b.step_conversion_rate ? a : b, results[1] || {});
return [{ json: { week: new Date().toISOString().slice(0,10), steps: results, biggest_drop_off: worstStep, overall_end_to_end_cr: results[results.length-1]?.overall_conversion_rate || 0 } }];

